import React from "react";
import ReactECharts from "echarts-for-react";

const Dashboard = () => {
  const chartOptions = {
    title: {
      text: "Sales Over Time",
    },
    tooltip: {},
    legend: {
      data: ["Sales Line", "Sales Bar"],
    },
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: [
      {
        type: "value",
        name: "Sales",
      },
      {
        type: "value",
        name: "Other Metric",
        position: "left",
        offset: 0,
      },
    ],
    series: [
      {
        name: "Sales Line",
        type: "line",
        data: [30, 40, 35, 50, 49, 60, 70],
      },
      {
        name: "Sales Bar",
        type: "bar",
        data: [20, 30, 25, 40, 35, 50, 60],
        yAxisIndex: 1,
      },
    ],
  };

  const barChartOptions = {
    title: {
      text: "Sales by Month",
    },
    tooltip: {},
    xAxis: {
      type: "category",
      data: ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul"],
    },
    yAxis: {
      type: "value",
    },
    series: [
      {
        name: "Sales",
        type: "bar",
        data: [20, 30, 25, 40, 35, 50, 60],
      },
    ],
  };

  const pieChartOptions = {
    title: {
      text: "Inspection Types",
    },
    tooltip: {},
    series: [
      {
        name: "Types",
        type: "pie",
        data: [
          { value: 30, name: "Inspections" },
          { value: 40, name: "Follow-ups" },
          { value: 30, name: "Re-inspections" },
        ],
      },
    ],
  };

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h2>Total Sales</h2>
          <p>$100,000</p>
        </div>
        <div className="kpi">
          <h2>Total Inspections</h2>
          <p>250</p>
        </div>
        <div className="kpi">
          <h2>Active Users</h2>
          <p>150</p>
        </div>
      </div>
      <ReactECharts option={chartOptions} />
      <ReactECharts option={barChartOptions} />
      <ReactECharts option={pieChartOptions} />
    </div>
  );
};

export default Dashboard;
